var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……귀환 보고.","JPN":"……帰還報告。","ENG":"... I’m back to report, Your Highness.","TWN":"……現況回報。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"허신 카미마엘의 소멸 확인.","JPN":"虚神カミマエルの消滅確認。","ENG":"The Hollow God Khamimael was eliminated.","TWN":"幻神卡米麥爾確定死亡。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"늑대가 신의 혼을 삼켰습니다.","JPN":"狼が神の魂を飲み込みました。","ENG":"The Wolf swallowed its soul.","TWN":"狼吞噬掉神的靈魂。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"훌륭하군. 반역자의 딸이여.","JPN":"見事だ。反逆者の娘よ。","ENG":"You did well, daughter of the traitor.","TWN":"非常出色，逆賊之女。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내 기대를 뛰어넘는 공적이다.","JPN":"私の期待を上回る功績だった。","ENG":"You exceed my expectations.","TWN":"你的功績遠超過我的期待。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면…… 이제 가문의 명예를 회복시켜 주실 수 있으십니까?","JPN":"それでは……これで一族の名誉を回復させていただけますでしょうか。","ENG":"Then... will you clear the name of my family now?","TWN":"那……現在可以幫我恢復家族的榮耀嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하.","JPN":"殿下。","ENG":"Your Highness.","TWN":"殿下？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"물론이다. 그런 하찮은 소원 따위는 충분히 들어 주고도 남을 만한 공적이야.","JPN":"勿論だ。そんなくだらぬ願いなど十分聞き入れてやれる功績だ。","ENG":"I could. To be honest, your contribution exceeds such a trivial wish.","TWN":"有什麼問題，你立下這麼大的功，幫你完成那點心願算什麼。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그, 그렇다면!","JPN":"そ、それでは！","ENG":"Th-then!","TWN":"那……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 거절한다.","JPN":"だが、断る。","ENG":"But I refuse.","TWN":"不過我拒絕。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"Huh?","TWN":"什麼……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"어, 어째서!!","JPN":"な、なぜですか！！","ENG":"B-but why?!","TWN":"為什麼！！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그건 네가 진정으로 원하는 것이 아니기 때문이지.","JPN":"それが貴様の本当の望みではないからだ。","ENG":"Because that’s not your true wish.","TWN":"因為那不是你真正想要的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"원하는 게 아니라니요? 대체, 무슨 말씀을……!","JPN":"望みではない、と？　いったい、どういう……！","ENG":"What do you mean, Your Highness? I don’t understand!","TWN":"不是我真正想要的？這是什麼意思……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"잘 떠올려 보아라.","JPN":"よく思い出してみろ。","ENG":"Think about it.","TWN":"你好好回想一下。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너를 처형장에서 구해 줬을 때, 나는 분명 네 진정한 소망을 이루어 주겠다고 했다.","JPN":"貴様を処刑場で救ったとき、私は確かに貴様の本当の望みを叶えてやると言った。","ENG":"When I saved you from execution, I promised that I was going to grant you something that you truly wish for.","TWN":"我在刑場救下你的時候曾經說過，會完成你真正的心願。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그렇게 숱한 세월이 지났는데도 넌 아직 그게 무엇인지 깨닫지 못한 모양이군.","JPN":"だが、これほど長い歳月が経ったというのに、\\n貴様はまだそれが何なのか気づいていないようだな。","ENG":"But after all these years, you still don’t know what that is.","TWN":"但是在經過那麼漫長的時間後，你似乎依舊不明白。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그런……. 말도 안되는 말씀을…….","JPN":"そんな……とんでもない話を……","ENG":"But... it doesn’t make sense...","TWN":"那是……什麼意思……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……허나 나는 자비로운 군주다.","JPN":"……しかし、私は慈悲深い君主である。","ENG":"However, I am a merciful ruler.","TWN":"……不過，我是仁慈的君王。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"비록 거짓된 소망이라고는 하나 공훈을 세운 부하가 원한다면 그 뜻을 이루어 주도록 하지.","JPN":"たとえ偽りの望みとはいえ、功績を立てた部下が望むなら叶えてやろう。","ENG":"Though your wish may be false, I will grant it, because you did serve me loyally.","TWN":"雖然這是個虛假的心願，但手下立下這麼大的功勞，我還是會替你達成。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 묻겠다. 반역자의 딸이여.","JPN":"だから問おう。反逆者の娘よ。","ENG":"So I ask you again, daughter of the traitor.","TWN":"所以我要問你，逆賊之女，"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너는 진정으로 가문의 명예를 되찾길 원하는가?","JPN":"貴様は心から一族の名誉を取り戻すことを望んでいるのか？","ENG":"Do you truly wish to clear the name of your family?","TWN":"你真正的心願是要恢復家族的榮耀嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"옛 친구를 배신하고, 영혼과 육체를 다하면서까지 그것을 원하는가?","JPN":"旧友を裏切り、魂と肉体を尽くしてまでそれを望んでいるのか？","ENG":"Do you really want it, after all these years, betraying your old friend, sacrificing your body and soul?","TWN":"背叛以前的朋友，出賣心靈和肉體也希望家族恢復榮耀嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"대답해라, 샬롯 마르티네즈. 그것이 네 진정한 소망인가?","JPN":"答えろ、シャーロット・マルチネス。それが貴様の本当の望みか？","ENG":"Answer me, Carlota Martinez. Is that what you truly wish?","TWN":"回答我！夏洛特 馬汀尼茲，那是你真正的心願嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하, 저는 오직……!","JPN":"殿下、私はただ……！","ENG":"Your Highness, all I want is...","TWN":"殿下，我 是為……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"가문은……","JPN":"一族は……","ENG":"The family...","TWN":"家族……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"가문이야말로……","JPN":"一族こそ……","ENG":"For the family...","TWN":"家族……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"오직 가문을 위해!!!","JPN":"一族のために！！","ENG":"All for the sake of the family!","TWN":"為家族而活！！！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"이렇게 만나게 된 것도 인연이니까, 진짜 친구 이상의 서비스 정신을 보여 줄게.","JPN":"これも何かの縁だし、\\n本当の友達以上のサービス精神ってやつを見せてあげるよ。","ENG":"I’ll help you like a friend. No, even better than a friend.","TWN":"既然能相遇就是緣份，我會用一顆服務朋友的心來服務你的！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L39_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아니야!","JPN":"違う！","ENG":"No!","TWN":"不是！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문 따위는! 불태울 가치도 없는 쓰레기야!!","JPN":"一族なんて！　燃やす価値すらないクズ同然だ！","ENG":"I don’t care about the family! It’s just worthless trash!!","TWN":"家族不過就是一把火燒掉也不足惜的垃圾！！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"난 그저 평범하게 살고 싶었어! 친구들과, 사랑하는 가족들과!","JPN":"私はただ平凡に暮らしたかった！　友達と、愛する家族と共に！","ENG":"All I wanted was a happy life! With my friends and family!","TWN":"我只想和朋友！和親愛的家人！一起過著平凡的日子！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"하지만 내겐 아무런 선택지도 없었어!","JPN":"でも、私には何の選択肢もなかった！","ENG":"But I had no choice!","TWN":"但我根本沒有選擇的餘地！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"내 인생은…… 피와 저주와…… 고통 뿐이었다고……","JPN":"私の人生は……血と呪いと………苦痛ばかりだった……","ENG":"My life... was filled with blood and curses... and pain...","TWN":"我的人生……就只有血緣、詛咒……和痛苦……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문 따위…… 뒈져 버리라지……","JPN":"一族なんて……くそ食らえ……","ENG":"My family.. be damned...","TWN":"家族什麼的……去死吧……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"할 수만 있다면 내 인생을 파괴한 가문의 인간들을 다시 살려내서라도 죽여버리고 싶어!","JPN":"できるなら私の人生をぶち壊した一族の連中を、\\nまた生き返らせてでも殺してやりたい！","ENG":"They destroyed my life! I would kill every member of my family if I could!","TWN":"可以的話，就算那些毀掉我人生的人復活，我也要殺掉他們！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"훌륭하다!","JPN":"素晴らしい！","ENG":"Excellent!","TWN":"非常好！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그것이 바로 네가 진정 원해야 하는 것, 복수다!","JPN":"それがまさに貴様が心から望むべきもの、復讐だ！","ENG":"That is what you truly wish! Vengeance!","TWN":"這就是你真正想要的，報仇！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"진정한 귀족의 의무가 무엇인지 깨달았구나.","JPN":"真の貴族の義務が何なのか、ようやく悟ったようだな。","ENG":"You finally realized the true calling of a noble.","TWN":"你終於明白什麼是貴族真正的義務。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이곳에서 그대를 정식으로 마르티네즈 백작, 아니 후작으로 봉하겠다.","JPN":"ここで貴様を正式にマルチネス伯爵、いや侯爵に封ずる。","ENG":"I am now officially entitling you as Count—no, Marquise Martinez.","TWN":"我在此宣布，正式封你為馬汀尼茲伯爵…不，是侯爵。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대는, 진정 위대한 귀족이다. 샬롯 마르티네즈 공.","JPN":"貴様は真の偉大な貴族だ。シャーロット・マルチネス卿。","ENG":"You really are a true noble, Marquise Martinez.","TWN":"你是真正偉大的貴族，夏洛特 馬汀尼茲侯爵。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……전하. 시간이 되었습니다.","JPN":"……殿下。時間になりました。","ENG":"Your Highness, it’s time.","TWN":"……殿下，時間差不多了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아, 벌써 그렇게 되었나? 내 실수로군.","JPN":"ああ、もうそんな時間か？　私としたことが。","ENG":"Oh, already? My bad.","TWN":"這麼快？是我沒注意到。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대도 함께하겠나? 마르티네즈 공.","JPN":"貴様もともにくるか？　マルチネス卿。","ENG":"Are you coming with me, Marquise Martinez?","TWN":"你也一起來嗎，馬汀尼茲侯爵？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……물론입니다.","JPN":"……無論です。","ENG":"... Of course, Your Highness.","TWN":"……當然！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"제 저주를 짓밟아 주신 전하와 함께하면 지옥의 끝까지라도 같이 가겠습니다.","JPN":"私の呪いを焼き払ってくださった殿下とならば、\\n地獄の果てまでご一緒します。","ENG":"You crushed the curse bestowed on me. I will follow you to the darkest corners of hell.","TWN":"是殿下救我脫離家族的詛咒，就算要下地獄我也願意去！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이. 구원기사단 전원, 집결을 마쳤다.","JPN":"レイ。救世騎士団は全員集結した。","ENG":"Ray. The Knights of Redemption are all here.","TWN":"雷伊， 救贖騎士團全員集合完畢。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"... Okay.","TWN":"……嗯。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"드디어…… 저희를 구원해 주시는 거군요, 구원자님!","JPN":"ついに……我々を救ってくださるのですね、救世主様！","ENG":"Finally... you’re here to save us, my Savior!","TWN":"救贖者大人…… 您終於要救贖我們了嗎？"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대는 참으로 성녀가 아니라 광대가 어울리는 인재로군.","JPN":"貴様は聖女ではなく、道化師が似合う人材だな。","ENG":"You’re more like a clown than a Saintess.","TWN":"你真的不適合當什麼聖女，比較適合去演戲。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"황실을 재건하면 반드시 궁정 광대로 임명하도록 하겠다, 루크레시아.","JPN":"皇室を再建したら是非とも宮廷道化師に任命してやろう、ルクレシア。","ENG":"When I rebuild my court, I will appoint you as my court jester, Lucrecia.","TWN":"等皇室重建後，我一定任命你為宮廷戲子，露可蕾西亞。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……누가 그런 모욕을 받아들인다고!","JPN":"……誰がそんな侮辱を受け入れると！","ENG":"You dare insult me!","TWN":"……你竟敢這樣羞辱我！"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그만. 루크레시아.","JPN":"よせ、ルクレシア。","ENG":"Stop, Lucrecia.","TWN":"不得無禮，露可蕾西亞。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하께서도 너그럽게 용서하십시오. 오래도록 기다려 온 날이 아닙니까.","JPN":"殿下もどうかお許し下さい。長きにわたり待ち望んでいた日ではないですか。","ENG":"Your Highness, please forgive her. We waited for this day for so long.","TWN":"還請殿下恕罪，別打壞殿下期待這麼久的好心情。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……좋다. 오늘은 즐거운 날이니 무례함을 참아 보기로 하지.","JPN":"……よかろう。今日はめでたい日だ、無礼を許す。","ENG":"Very well. I won’t ruin this great day.","TWN":"……好吧，今天這麼開心，我就姑且忍耐她的無禮。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"시작해라, 평민!","JPN":"始めろ、平民！","ENG":"Peasant, start the ceremony!","TWN":"開始吧，平民！"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……わかりました。","ENG":"... Yes, Your Highness.","TWN":"……是。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"당신의 어린 늑대는…… 이곳에서 스승을 만났고.","JPN":"あなたの幼き狼は……ここで師匠に出会い……","ENG":"Your young Wolf met her Master here...","TWN":"你的幼狼……在這裡遇見師父。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"친우의 희생을 경험했으며…….","JPN":"親友の犠牲を経験し……","ENG":"She saw her friend’s sacrifice...","TWN":"經歷到摯友的犧牲……"},"stage":{"bg":"MAINSTREAM_344010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"광신자로부터 세상을 구해 내었고…….","JPN":"狂信者から世界を救い出し……","ENG":"Then she saved the world from a fanatic...","TWN":"從狂信徒手中拯救世界……"},"stage":{"bg":"MAINSTREAM_5508012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리하여 마침내 신을 멸하였다.","JPN":"そうして、ついに神を滅ぼした。","ENG":"And finally, she killed a god.","TWN":"因此終於除滅神。"},"stage":{"bg":"MAINSTREAM_805","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이. 네 차례야.","JPN":"レイ、お前の番だ。","ENG":"Ray, it’s your turn now.","TWN":"雷伊，輪到你了。"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"이로써 그대가 낳은 씨앗이 수확의 때가 왔음을 알리노니……","JPN":"これよりそなたが蒔いた種に、収穫の時が来たことを告げる……","ENG":"Now, your seed has sprouted, and the time of harvest is at hand...","TWN":"你撒下的種子，現在是收成的時候……"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"네헤모트의 이름으로, 클리포트 게임의 시작을…….","JPN":"ネヘモトの名の下に、クリフォトゲームの開始を……","ENG":"In the name of Nehemoth, I request...","TWN":"我以貝赫莫特之名，請求逆卡巴拉遊戲……"},"stage":{"bg":"MAINSTREAM_806","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"바란다.","JPN":"望む。","ENG":"... to begin the Qliphoth Game.","TWN":"開始。"},"stage":{"bg":"MAINSTREAM_807","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT_02"},{"id":"L2_1","type":"dialog","speaker":"THAMIEL_NULL_NULL_NULL","text":{"KOREA":"<color=#ff3636>……허락한다.</color>","JPN":"<color=#ff3636>……許可する。</color>","ENG":"<color=#ff3636>I grant it.</color>","TWN":"<color=#ff3636>……准許。</color>"},"stage":{"bg":"MAINSTREAM_807","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};